    // ... for each output position (oi)
    // Load all KD*KH*KW input values from LDS
    #pragma unroll
    for(int d = 0; d < KD; d ++) {
        #pragma unroll
        for(int h = 0; h < KH; h++) {
            #pragma unroll
            for(int w = 0; w < KW; w+=KW_PACK) {
                int src_off = d*(padded_H * padded_W) + (PaddingH + h - KH/2)*padded_W + (PaddingW + w - KW/2);
                reinterpret_cast<uint32_t&>(input_reg[d][h][w/KW_PACK]) = ds_read_b32(s_input + srci0, src_off*sizeof(IO_DTYPE));
            }
        }
    }
    // Wait for loads
    s_waitcnt_lgkmcnt<0>();
    __builtin_amdgcn_sched_barrier(0);
    // Compute MACs for KW_PACK output values
    #pragma unroll
    for (int p = 0; p < KW_PACK; p++) {
        float sum = bias_value;
        #pragma unroll
        for(int d = 0; d < KD; d ++) {
            #pragma unroll
            for(int h = 0; h < KH; h++) {
                #pragma unroll
                for(int w = 0; w < KW; w+=2) {
                    // ... MACs
                }
            }
        }
        output[oh * oW + ow + p] = (IO_DTYPE)(sum);
    }
}
```

The `input_reg[KD][KH][KWR][KW_PACK]` = [3][5][3][2] is 90 uint32_t values = 360 bytes. The weights are 75 float32 values = 300 bytes.

So we have ~660 bytes of register state that's live simultaneously during the MAC loop.

The optimization is to interleave: for each (d, h) plane, load the needed inputs and immediately compute the MACs for that plane, rather than loading everything first.

