```cpp
// conv
constexpr int num_outputs = BLOCK_H * BLOCK_W;
constexpr int KW_PACK = 2;
constexpr int KWR = div_up(KW, KW_PACK);
static_assert(BLOCK_W % 2 == 0);

for (int oi = KW_PACK*threadIdx.x; oi < num_outputs; oi += KW_PACK*blockDim.x) {
    const int oh = oi / BLOCK_W;
    const int ow = oi % BLOCK_W;
    const int ih = oh;
    const int iw = ow;
    const int srci0 = (ih) * padded_W + (iw);

    // Initialize sums for both output values (p=0 and p=1)
    float sum0 = bias_value;
    float sum1 = bias_value;

    // Interleave load and compute per (d, h) plane
    #pragma unroll
    for(int d = 0; d < KD; d++) {
        #pragma unroll
        for(int h = 0; h < KH; h++) {
            // Load inputs for this (d, h) plane only
            uint32_t iword[KWR];
            #pragma unroll
            for(int w = 0; w < KW; w+=KW_PACK) {
                int src_off = d*(padded_H * padded_W) + (PaddingH + h - KH/2)*padded_W + (PaddingW + w - KW/2);
                iword[w/KW_PACK] = ds_read_b32(s_input + srci0, src_off*sizeof(IO_DTYPE));
            }

            s_waitcnt_lgkmcnt<0>();
            __builtin_amdgcn_sched_barrier(0);

            // Extract BF16 values from each word
            // iword[k] has two BF16: iword[k] as __hip_bfloat16* = [v[2k], v[2k+1]]
            // For p=0: need v[0], v[1], v[2], v[3], v[4]
            // For p=1: need v[1], v[2], v[3], v[4], v[5]

            #pragma unroll
            for(int w = 0; w < KW; w+=2) {
                // p=0
                v_fmac_f32(sum0, weight_reg[d][h][w+0], (float)(__hip_bfloat16{reinterpret_cast<uint32_t&>(iword[w/KW_PACK]) & 0xFFFF}));
                if (w+1 < KW)
                    v_fmac_f32(sum0, weight_reg[d][h][w+1], (float)(__hip_bfloat16{(reinterpret_cast<uint32_t&>(iword[w/KW_PACK]) >> 16) & 0xFFFF}));

                // p=1
                if (w > 0)
                    v_fmac_f32(sum1, weight_reg[d][h][w-1], (float)(__hip_bfloat16{(reinterpret_cast<uint32_t&>(iword[(w-1)/KW_PACK]) >> 16) & 0xFFFF}));
                if (w+1 < KW)
                    v_fmac_f32(sum1, weight_reg[d][h][w+0], (float)(__hip_bfloat16{reinterpret_cast<uint32_t&>(iword[w/KW_PACK]) & 0xFFFF}));
            }
        }
    }

    output[oh * oW + ow + 0] = (IO_DTYPE)(sum0);
    output[oh * oW + ow + 1] = (IO_DTYPE)(sum1);
}
```

